var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우…… 어머니도 참 매몰차셨네요.","JPN":"ふう……お母様も冷酷ですわね。","ENG":"*Sigh...* Mother was a heartless one, was she not?","TWN":"哀……母親真無情啊。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"영지민들 마룻바닥 밑에 죽은 사람들 유골이 이렇게 잔뜩 쌓여 있는데….","JPN":"領地民の床下に死んだ人の遺骨がこんなにたくさん積み上げられているのに……","ENG":"She must have known about the mountain of human bones piled up right below the floor where the residents live...","TWN":"領地居民們的地板底下這樣堆滿了死人的遺骨……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 아무 조치도 안 하신 걸까요? ","JPN":"どうして何もされなかったのでしょう？ ","ENG":"But why did she not do anything about it? ","TWN":"她為什麼沒採取任何措施呢？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"긍정적으로 생각해. 네 엄마가 저지른 일들 덕분에 우린 매일매일이 보람차잖아.","JPN":"ポジティブに考えなよ。アンタのお母さんがしでかしたことのおかげで、アタシたちは毎日仕事のやり甲斐があるんだからさ。","ENG":"Look on the bright side! Because of her, you and I are making the most of every day!","TWN":"往好的方面想。正因為你媽媽做的那些事，我們才能每一天都過得充實又意義。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"침식체라도 안 나타나면 따분해서 어떻게 살겠어?","JPN":"侵食体でも現れなかったら退屈すぎて死んじゃうよ。","ENG":"How bored would we have been if there weren't any C.O.s to kill, right?","TWN":"要是沒有侵蝕體出現，我們的生活得有多無聊啊？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 하루라도 좋으니까 영지에 아무 일 없이 넘어가면 좋겠어요.","JPN":"私は一日でもいいから領地に何事も起こらずに終わる日があってほしいですわ。","ENG":"All I wish is that for a single day, nothing happens around here.","TWN":"哪怕只有一天也好，我希望領地什麼事都沒有。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"결국 수색에서 건진 거라고는 인식표뿐이었네요.","JPN":"結局捜索で得たものは認識票だけでしたわね。","ENG":"The only thing worthwhile with the search was this dog tag.","TWN":"結果只找到這個識別牌呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"나머지 유골들은 신원을 확인할 방법도 마땅치 않고…….","JPN":"残りの遺骨は身元を確認する方法もないですし……","ENG":"And for the rest of them, there is no way to confirm who they were...","TWN":"剩下的遺骨，也沒有什麼方法可以確認身份……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"계속 이런 사건이 일어나지 않으려면, 역시 어떻게든 해야......","JPN":"こういった事件をまた起こさないようにするためには、やはり何とかしないと……","ENG":"If I do not want anything like this to happen, then I must–","TWN":"如果不想繼續發生這樣的事件，果然還是得想想……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"레지나, 영지의 앞날에 대해 고민하는 것도 좋은데 말이야.","JPN":"レジーナ、領地の将来について悩むのもいいけどさ。","ENG":"Regina, I respect how you always think of the future of your estate, but...","TWN":"蕾佳娜，考慮領地的未來的確是好事。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"거기 계속 서 있으면 큰일날걸?","JPN":"ずっとそこに立ってると大変なことになるよ？","ENG":"We're gonna be in big trouble if we stay here, you know?","TWN":"不過你一直站在那裡的話，可能會出大事喔？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 침식체는 방금 그걸로 전부 해치운 것 아니었나요?","JPN":"え？　先ほどのあれで侵食体は全部処理したのでは？","ENG":"Huh? That was not the last of the C.O.s?","TWN":"什麼？侵蝕體剛才不是全都解決掉了嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"응. 그런데 우리가 워낙 요란하게 싸웠잖아.","JPN":"うん。でもアタシたち、派手に戦ったじゃん？","ENG":"Yeah, but that was one heck of a fight.","TWN":"嗯，不過我們剛才鬧出的動靜有點大不是嘛。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그 바람에 살짝쿵 위태위태하던 천장이 무너지기 직전이거든.","JPN":"そのせいで、どうにかもっていた天井が今にも崩れそうなんだよね。","ENG":"And due to that, the ceiling is barely holding on, you know?","TWN":"所以，原本就有點岌岌可危的天花板，很快就要塌了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……앗.","JPN":"……あっ。","ENG":"Huh...?!","TWN":"……啊。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님. 지시하신 대로 외지인의 총에 맞은 주민은 수술을 마쳤습니다.","JPN":"副学会長。ご指示どおり、よそ者に銃で撃たれた住民の手術は終わりました。","ENG":"Vice President, the surgery you ordered us to perform on the resident who was shot by the outlander went well.","TWN":"副學會長，按照你的指示，給被外地人槍擊的居民做了手術。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAN_NPC_ESPR2_A","text":{"KOREA":"감사합니다. 호수를 찾으러 다니기도 바쁘실 텐데 저희 같은 것들을 돌봐 주시다니…….","JPN":"ありがとうございます。湖を探すことでもお忙しいはずなのに、私たちの面倒まで……","ENG":"Thank you for taking care of us. I know you must be busy searching for the Lake, ma'am...","TWN":"謝謝你。尋找湖水就夠你忙的了，還要照顧我們這些人……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 여러분은 영지의 주민으로서 안전과 편의를 보장 받을 권리가 있어요.","JPN":"いいえ。領地住民は安全と利便を享受する権利があります。","ENG":"No, as a resident of the estate, you have the right to be safe and comfortable.","TWN":"沒關係，各位都是領地的居民，有權利得到安全和便利的保障。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당연한 일에 감사할 필요는……","JPN":"当たり前のことに感謝する必要は……","ENG":"There is no need to thank me for somethi–","TWN":"這些都是我應該做的，不用說謝……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":" 에취!!","JPN":" くしゅん！！","ENG":" Achoo!","TWN":"哈啾！！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"자, 여기 수건.","JPN":"はい、タオル。","ENG":"Here's a handkerchief for you.","TWN":"手帕給你。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그러게 왜 그 구정물에 빠지고 그래. 감기도 잘 걸리면서.","JPN":"なんであの汚い水に落ちちゃうかなあ。風邪もよくひくくせに。","ENG":"Of course, the person who gets colds easily just had to trip and fall into a puddle of dirty water.","TWN":"所以說啊，你幹嘛要掉進污水裡。本來你就容易感冒。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"천장이 무너지려는 걸 바로 안 알려 주고 뜸들이던 게 누구였죠?","JPN":"天井が崩れようとしていることをすぐに知らせずに、勿体ぶっていたのは誰ですの？","ENG":"Do I have to remind you who did not tell me immediately that the ceiling was about to collapse?","TWN":"是誰沒有及時告訴我天花板要塌了，一直在那看好戲？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"저…… 부학회장님, 이걸 받아 주실 수 있을까요?","JPN":"あの……副学会長様、これを受け取ってください。","ENG":"Um... ma'am? I want you to have this.","TWN":"那個……副學會長，你能收下這個嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 이 바구니를요...?","JPN":"うん？　このカゴは……？","ENG":"Hmm? A basket?","TWN":"嗯？這個籃子嗎……？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"오우, 열매가 가득 들어 있네? 레지나한테 주려고 따 왔나 봐.","JPN":"うわ、木の実がいっぱいだね。レジーナにあげたくて摘んできたんじゃない？","ENG":"Ooh, it's got fruit inside it. I guess she went and picked them for you.","TWN":"哇喔，裡面裝滿了果實呢？好像是為了送給蕾佳娜才摘的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"네. 달여 먹으면 감기에 좋다고 어른 분들께서 알려 주셨어요.","JPN":"はい。煎じて飲めば風邪によく効くと教わりました。","ENG":"Yes. The elders told me that it's good for treating colds if you brew them into medicine.","TWN":"是的。長輩們說過用這個熬點水喝下去，感冒比較快好。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"부학회장님께서 늘 추위로 고생하신다는 얘기를 들었거든요.","JPN":"副学会長様がいつも冷えで苦労されていると聞いて。","ENG":"I heard that you are always suffering from colds, ma'am.","TWN":"我聽說副學會長一直很怕冷。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고마워요. 제가 영지에 돌아와서 받은 최고의 선물이에요.","JPN":"ありがとう。私が領地に戻ってから貰ったものの内で最高のプレゼントですわ。","ENG":"Thank you. This is the best gift I have ever received after coming back to the estate.","TWN":"謝謝你。這是我回到領地後，收過最好的禮物。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"섭섭하게 무슨 말씀을. 레지나에겐 내가 있잖아.","JPN":"それは寂しいなぁ。レジーナにはアタシがいるじゃん。","ENG":"Seriously? But you have me.","TWN":"你這麼說的話，太讓我傷心了。蕾佳娜還有我不是嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신은 제 인생의 재난이고요.","JPN":"あなたは私の人生の災難ですわ。","ENG":"You are the greatest pain in my butt.","TWN":"你是我人生的災難。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L43_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그럴 수가~","JPN":"そんな～","ENG":"Sheesh!","TWN":"怎麼會～"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데…… 저희 혹시 다른 일로 만난 적 있었나요?","JPN":"ところで……もしかして以前に別のことで会ったことがあるかしら？","ENG":"But, um... Have we ever met before?","TWN":"不過……我們之前因為別的事見過面嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"앗. 네. 작은 언니가 얼마 전 영지를 나가 다른 도시에서 살게 되었거든요.","JPN":"あっ。はい。姉が少し前に領地を出て違う街に住むことになったんですが。","ENG":"Oh, yes. One of my sisters recently moved out of the estate to live in another city.","TWN":"啊，是的。我的三姊不久前離開領地，去別的城市生活了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"학회의 도움 없이 영지 바깥에서 살기로 결심한 게 정말 대견하다고 칭찬해 주셨어요.","JPN":"学会の支援なしに領地の外で暮らすと決めたことを、本当に感心だといって褒めてくださいました。","ENG":"You said it was brave of her to live outside of the estate without depending on the Society.","TWN":"當時副學會長說，她沒有學會的幫助，還能下決心在領地外面生活，值得稱讚呢。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아. 기억해요. 그 학생 가족이었군요.","JPN":"あ。覚えていますわ。あの学生のご家族だったのですね。","ENG":"Oh, yes. I remember now. You are her family.","TWN":"啊，我想起來了。你是那個學生的家人。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"네. 부학회장님 덕분이에요. 학회원이 아니어도 영지를 나갈 수 있게 해 주셨으니까요.","JPN":"はい。副学会長様のおかげです。学会員じゃなくても領地から出られるようにしてくれましたから。","ENG":"Yes. Thanks to you, we are now able to live outside the estate even if we aren't Society members.","TWN":"是的，這都是托副學會長的福。就算姊姊不是學會成員，你還是讓她離開了領地。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"언니들도 무척 기뻐했어요.","JPN":"姉たちもとても喜んでいました。","ENG":"My sisters were ecstatic too.","TWN":"姊姊們也都很高興。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"흥, 좋은 재능을 가지고 태어났으면 학회를 위해 써야 하는 법인데…….","JPN":"ふん、優秀な才能を持って生まれたなら学会のために使うのが正解だろう……","ENG":"Hmph. If she had talent, then she should be working for the Society...","TWN":"哼，有優秀的才能，就應該為學會效力……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"외지인들 사이에서 얼마나 버티겠어. 금방 도망쳐 오겠지.","JPN":"よそ者の間ではそう長く耐えられないはずだ。すぐ逃げ帰って来るよ。","ENG":"She's not going to last that long outside with the outlanders. She'll be crawling back in no time.","TWN":"我看她在一群外地人中間能撐多久。應該很快就會逃回來吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다들 정숙하세요.","JPN":"皆さん、ご静粛に。","ENG":"Everyone, silence.","TWN":"大家都別說了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"오래된 편견을 하루 아침에 바꿀 수 있다고는 생각하지 않습니다.","JPN":"古い偏見をすぐに変えられるとは思いません。","ENG":"I do not think that old prejudice can be obliterated overnight.","TWN":"我不認為根深蒂固的偏見會在一夕間改變。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 바깥 세상이 위험하지도 야만스럽지도 않은 건 여러분이 가장 잘 아실 텐데요?","JPN":"ですが、外の世界が危険でも野蛮でもないことは皆さんが一番よくおわかりのはずです。","ENG":"However, I am also certain that the world outside is neither dangerous nor barbaric.","TWN":"但是外面的世界既不危險，也不野蠻，這一點大家應該都很清楚吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다른 건 몰라도, 이 건에 대해서만큼은 여기서 확정 짓고 가야겠습니다.","JPN":"他の件はともかく、この件についてだけはこの場で決定します。","ENG":"I do not know about anything else, but I do want to settle this before moving on.","TWN":"別的先不說，關於這件事，我要在這裡再確定一下。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"바구니는 잘 받을게요. 작은 언니 소식이 오면 다음에 저에게도 얘기해 주세요.","JPN":"カゴはありがたく頂戴しますわ。お姉さんから連絡が来たら、私にも教えてください。","ENG":"Thank you for the gift basket. Tell me more about how your sister is doing after you hear back from her, please.","TWN":"籃子我收下了。你三姊傳來消息的話，下次再告訴我吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록, 콜록……!","JPN":"ゲホ、ゲホ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳……！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"부, 부학회장님. 괜찮으세요?","JPN":"ふ、副学会長様。大丈夫ですか？","ENG":"V-vice President! Are you okay?","TWN":"副…副學會長，你沒事吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록……. 괜찮아요. 감기는 자주 걸리는 편입니다.","JPN":"ゲホッ……大丈夫です。風邪はよくひく方ですから。","ENG":"*Cough!* I'm okay. Just a cold, that is all.","TWN":"咳咳……我沒事。就是經常感冒。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 저희는 이만 돌아가기로 하죠. 벽난로에 몸을 좀 녹여야겠어요.","JPN":"リベット、私たちはもう戻りましょう。暖炉で体を温めないと。","ENG":"Rivet, shall we start heading back home? I need to warm myself near a fire.","TWN":"里維，我們回去吧。我得在壁爐前暖暖身子。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAN_NPC_ESPR2_C","text":{"KOREA":"다들 들었지? 부학회장님 앞에서는 입조심해.","JPN":"みんな、聞いただろう？　副学会長の前では口を慎め。","ENG":"You heard her. Watch what you say around Ms. Vice President.","TWN":"大家都聽見了吧？在副學會長面前說話都小心點。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MAN_NPC_ESPR2_B","text":{"KOREA":"외지인에게 무척이나 관대하시단 말이야. 영지 바깥에서 오래 지내셔서 그런가….","JPN":"よそ者に寛大すぎるんだよな。領地の外で長く暮らされていたからか……","ENG":"She's more forgiving of outlanders than we are. Maybe it's because she's lived out there for a long time...","TWN":"她對外地人很寬容。不知是不是因為在領地外面生活了很久的緣故……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MAN_NPC_ESPR2_A","text":{"KOREA":"우리는 부학회장님 말씀에 얌전히 따르기만 하면 돼. 그만 떠들고 일이나 하러 가지.","JPN":"俺たちは副学会長のお言葉にただ従っていればいいんだ。おしゃべりはそのくらいにして仕事だ、仕事。","ENG":"All we need to do is listen and follow her words. Now, enough chatting and let's get back to work.","TWN":"我們只需要乖乖遵從副學會長說的話就行。少在哪邊說東說西的，去做事吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"부학회장님……. 괜찮으실까.","JPN":"副学会長様……大丈夫かな。","ENG":"Will she... be okay?","TWN":"副學會長……會沒事吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"아무 탈 없으셔야 할 텐데…….","JPN":"何ともないといいけど……","ENG":"I hope she doesn't get sick...","TWN":"希望她平安無事……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};